class Solution:
    def calculateTax(self, brackets, income):
        total = 0.0
        for i in range(len(brackets)):
            lo = brackets[i - 1][0] if i > 0 else 0
            hi = brackets[i][0]
            pct = brackets[i][1]
            taxable = max(0, min(income, hi) - lo)
            total += taxable * pct / 100.0
        return total

