class Solution:
    def calculateTax(self, brackets, income):
        total = 0.0
        prev = 0
        remaining = income
        for upper, percent in brackets:
            if remaining <= 0:
                break
            width = min(remaining, upper - prev)
            total += width * percent / 100.0
            remaining -= width
            prev = upper
        return total

