var calculateTax = function(brackets, income) {
    let total = 0;
    let prev = 0;
    let remaining = income;
    for (const [upper, percent] of brackets) {
        if (remaining <= 0) break;
        const width = Math.min(remaining, upper - prev);
        total += width * percent / 100;
        remaining -= width;
        prev = upper;
    }
    return total;
};
